chart.config_raw:
const ctx = document.getElementById('storageChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: [
      '(1) 8B / ShareGPT',
      '(2) 8B / LongBench',
      '(3) 70B / ShareGPT',
      '(4) 70B / LongBench'
    ],
    datasets: [
      {
        label: 'Prefill instance',
        data: [1.68, 24.59, 1.65, 6.58],
        backgroundColor: '#4dabf7',
        borderRadius: 4
      },
      {
        label: 'Decode instance',
        data: [57.33, 99.93, 52.88, 94.54],
        backgroundColor: '#f6ad55',
        borderRadius: 4
      }
    ]
  },
  options: {
    animation: false,
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      title: {
        display: true,
        text: 'Peak KV Cache Usage (%) — Disaggregated Storage Imbalance',
        font: { size: 14, weight: '700', family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
        color: '#1a1a1a',
        padding: { bottom: 16 }
      },
      legend: {
        labels: {
          font: { size: 12, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
          color: '#4a5568',
          usePointStyle: true,
          pointStyle: 'rectRounded'
        }
      },
      tooltip: {
        callbacks: {
          label: function(context) {
            return context.dataset.label + ': ' + context.parsed.y + '%';
          }
        }
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 110,
        ticks: {
          callback: function(value) { return value + '%'; },
          font: { size: 11 },
          color: '#718096'
        },
        grid: { color: '#e2e8f0' },
        title: {
          display: true,
          text: 'Peak KV Cache Usage',
          font: { size: 12 },
          color: '#718096'
        }
      },
      x: {
        ticks: {
          font: { size: 11 },
          color: '#718096'
        },
        grid: { display: false }
      }
    }
  }
});
